Here is a fresh, clean, and deobfuscated implementation of the physics simulation. 

The original code used obfuscated names, control-flow flattening (switch statements inside loops), and string literal hiding, but underneath it implements a spring-based physics simulation with particle streams and a camera follow system. I have given all variables, functions, and parameters highly readable and logical names based on their purpose.

```javascript
/**
 * Clean Implementation of Graph/Particle Physics Simulation
 */

// Math constants matching the original configuration
const Math_TWO_PI = 6.283;
const Math_PHI = 1.618;
const Math_SQRT2_2 = 0.707;

// Physics parameters decoded from the original script
const config = {
    attraction: 4000,
    repulsionCoeff: 0.004,
    friction: 0.92,       // Originally mislabeled as 'amplification'
    centerPull: 0.0003,
    streamMax: 40,
    streamDecay: 0.04,
    cameraTheta: 0.06     // Originally named 'theta'
};

class Node {
    constructor(id, label, r, x, y) {
        this.id = id;
        this.label = label;
        this.r = r;
        this.x = x;
        this.y = y;
        this.vx = 0;
        this.vy = 0;
    }
}

// Reconstructed base nodes and their start coordinates (hex -> decimal)
const nodes = [
    new Node('hub',     'Hub',     26, 400, 300),
    new Node('alpha',   'Alpha',   16, 500, 200),
    new Node('beta',    'Beta',    16, 300, 400),
    new Node('gamma',   'Gamma',   14, 250, 180),
    new Node('delta',   'Delta',   14, 550, 380),
    new Node('epsilon', 'Epsilon', 12, 350, 150)
];

// Spring connections forming the graph mesh
const links = [
    { a: 'hub',   b: 'alpha',   rest: 160, k: 0.006 },
    { a: 'hub',   b: 'beta',    rest: 160, k: 0.005 },
    { a: 'hub',   b: 'gamma',   rest: 170, k: 0.004 },
    { a: 'hub',   b: 'delta',   rest: 170, k: 0.004 },
    { a: 'hub',   b: 'epsilon', rest: 180, k: 0.003 },
    { a: 'alpha', b: 'beta',    rest: 200, k: 0.002 },
    { a: 'gamma', b: 'delta',   rest: 220, k: 0.002 },
    { a: 'alpha', b: 'epsilon', rest: 200, k: 0.002 }
];

const camera = { x: 400, y: 300, zoom: 1 };
const targetCamera = { x: 400, y: 300, zoom: 1 };

const particles = [];
let tickCount = 0;

function getNodeById(id) {
    return nodes.find(n => n.id === id) || null;
}

function updatePhysics() {
    // 1. Repulsion interaction between all pairs of nodes (Inverse square law)
    for (let i = 0; i < nodes.length; i++) {
        for (let j = i + 1; j < nodes.length; j++) {
            const dx = nodes[i].x - nodes[j].x;
            const dy = nodes[i].y - nodes[j].y;
            const distSq = dx * dx + dy * dy;
            const dist = Math.sqrt(distSq) || 1;

            const force = config.attraction / distSq;
            const fx = (dx / dist) * force;
            const fy = (dy / dist) * force;

            nodes[i].vx += fx;
            nodes[i].vy += fy;
            nodes[j].vx -= fx;
            nodes[j].vy -= fy;
        }
    }

    // 2. Spring forces for linked node pairs (Hooke's law)
    for (const link of links) {
        const nodeA = getNodeById(link.a);
        const nodeB = getNodeById(link.b);
        if (!nodeA || !nodeB) continue;

        const dx = nodeB.x - nodeA.x;
        const dy = nodeB.y - nodeA.y;
        const dist = Math.sqrt(dx * dx + dy * dy) || 1;
        const diff = dist - link.rest;

        const force = (link.k || config.repulsionCoeff) * diff;
        const fx = (dx / dist) * force;
        const fy = (dy / dist) * force;

        nodeA.vx += fx;
        nodeA.vy += fy;
        nodeB.vx -= fx;
        nodeB.vy -= fy;
    }

    // 3. Central gravity pull, velocity friction, and integration updates
    for (const node of nodes) {
        node.vx += (400 - node.x) * config.centerPull;
        node.vy += (300 - node.y) * config.centerPull;

        node.vx *= config.friction;
        node.vy *= config.friction;

        node.x += node.vx;
        node.y += node.vy;
    }
}

function emitParticle() {
    if (particles.length >= config.streamMax) return;

    const node = nodes[Math.floor(Math.random() * nodes.length)];
    const angle = Math.random() * Math_TWO_PI;
    const speed = 0.3 + Math.random() * Math_SQRT2_2;

    particles.push({
        x: node.x,
        y: node.y,
        vx: Math.cos(angle) * speed,
        vy: Math.sin(angle) * speed,
        age: 0,
        maxAge: 800 + Math.random() * 1200, // Hex 0x320 & 0x4b0 
        size: 0.8 + Math.random() * Math_PHI * Math_SQRT2_2
    });
}

function updateParticles() {
    const decayMultiplier = 1 - config.streamDecay * 0.125;

    for (let i = particles.length - 1; i >= 0; i--) {
        const p = particles[i];
        p.age++;

        if (p.age > p.maxAge) {
            particles.splice(i, 1);
            continue;
        }

        p.vx *= decayMultiplier;
        p.vy *= decayMultiplier;

        p.x += p.vx;
        p.y += p.vy;
    }
}

function updateCamera() {
    camera.x += (targetCamera.x - camera.x) * config.cameraTheta;
    camera.y += (targetCamera.y - camera.y) * config.cameraTheta;
    camera.zoom += (targetCamera.zoom - camera.zoom) * config.cameraTheta;
}

function loop() {
    updatePhysics();
    updateParticles();
    updateCamera();

    // Emit particle every 3rd tick
    if (tickCount % 3 === 0) {
        emitParticle();
    }
    tickCount++;
}

// Bootstrap loop, matches 0x10 ms
setInterval(loop, 16); 
